const body = $json.body || $json;
return [{
  json: {
    phone: String(body.phone || body.from || '').trim(),
    leadName: body.name || '',
    messageText: body.message || body.text || '',
    whatsappMessageId: body.messageId || body.id || '',
    receivedAt: new Date().toISOString(),
    channel: 'WhatsApp',
    subject: ''
  }
}];

const jiraFields = {
  canalSeguimiento: 'customfield_10040',
  fechaDiagnostico: 'customfield_10041',
  tierPropuesto: 'customfield_10042',
  agenteIa: 'customfield_10043',
  importeSetup: 'customfield_10044',
  numeroToque: 'customfield_10045',
  proximaAccion: 'customfield_10046',
  fechaVencimiento: 'customfield_10047',
  notas: 'customfield_10048',
  sentimiento: 'customfield_10049',
  resumenConversacion: 'customfield_10050',
  fechaUltimoContacto: 'customfield_10051',
  emailLead: 'customfield_10052',
  telefonoWhatsapp: 'customfield_10053',
  empresa: 'customfield_10054',
  nombreContacto: 'customfield_10055',
  gmailThreadId: 'customfield_10056',
  ultimoMessageIdProcesado: 'customfield_10057',
  errorTecnico: 'customfield_10058'
};

const config = {
  jiraBaseUrl: 'https://greenpc.atlassian.net',
  projectKey: 'REEMPLAZAR_PROJECT_KEY',
  adminEmail: 'REEMPLAZAR_ADMIN_EMAIL',
  openaiModel: 'o4-mini',
  whatsappMode: 'simulado',
  whatsappWebhookUrl: 'REEMPLAZAR_WHATSAPP_WEBHOOK_URL',
  timezone: 'Europe/Madrid',
  businessHours: {
    start: 9,
    end: 18,
    days: [1, 2, 3, 4, 5]
  },
  confidenceThreshold: {
    auto: 0.80,
    review: 0.60
  }
};

return items.map(item => ({ json: { ...item.json, jiraFields, config } }));

const phone = ($json.phone || '').replace(/"/g, '\\"');
const jql = `project = "${$json.config.projectKey}" AND "Teléfono WhatsApp" ~ "${phone}" AND status not in ("Firmado", "Descartado")`;
return [{ json: { ...$json, jiraSearchJql: jql, jiraSearchUrl: `${$json.config.jiraBaseUrl}/rest/api/3/search?jql=${encodeURIComponent(jql)}&maxResults=5` } }];

const search = $json;
const base = $items('Config Jira + campos')[0].json;
const issues = search.issues || [];
return [{ json: { ...base, jiraSearchResult: search, leadFound: issues.length === 1, multipleLeadsFound: issues.length > 1, issue: issues[0] || null } }];

const f = $json.jiraFields;
const issue = $json.issue;
const fields = issue.fields || {};
return [{
  json: {
    ...$json,
    issueKey: issue.key,
    issueId: issue.id,
    issueStatus: fields.status?.name || '',
    currentMessageId: $json.whatsappMessageId,
    lastProcessedMessageId: fields[f.ultimoMessageIdProcesado] || '',
    isDuplicateMessage: Boolean($json.whatsappMessageId && fields[f.ultimoMessageIdProcesado] === $json.whatsappMessageId),
    currentTouch: fields[f.numeroToque]?.value || 'Sin toque',
    currentSummary: fields[f.resumenConversacion] || '',
    nombreContacto: fields[f.nombreContacto] || $json.leadName || '',
    canalSeguimiento: fields[f.canalSeguimiento]?.value || 'WhatsApp',
    leadEmail: fields[f.emailLead] || '',
    gmailMessageId: $json.whatsappMessageId,
    gmailThreadId: ''
  }
}];

const systemPrompt = `Eres un clasificador operativo para el seguimiento comercial postdiagnóstico de Myutopia.

Tu tarea es interpretar mensajes de leads y devolver únicamente JSON válido.

No inventes datos. No inventes fechas, precios, condiciones, respuestas técnicas ni compromisos comerciales.

Si el mensaje contiene una pregunta técnica, una objeción importante, una duda compleja o una intención ambigua, debes escalar a administrador.

Intenciones válidas:
- accepts_proposal
- signed
- asks_question
- price_objection
- requests_technical_meeting
- postpones
- rejects
- ambiguous
- other

Sentimientos válidos:
- Entusiasta
- Dudoso
- Molesto
- Frío
- Neutral
- No detectado

Devuelve solo este JSON:
{
  "intent": "",
  "confidence": 0,
  "sentiment": "",
  "summary": "",
  "notes": "",
  "extracted_follow_up_date": null
}`;

const userPrompt = `Canal: ${$json.channel}
Asunto: ${$json.subject}
Mensaje del lead:
${$json.messageText}

Estado actual en Jira: ${$json.issueStatus}
Nº de toque actual: ${$json.currentTouch}
Resumen previo: ${$json.currentSummary}

Clasifica la intención del mensaje.`;

return [{
  json: {
    ...$json,
    openaiPayload: {
      model: $json.config.openaiModel,
      input: [
        { role: "system", content: systemPrompt },
        { role: "user", content: userPrompt }
      ],
      text: { format: { type: "json_object" } }
    }
  }
}];

const base = $items('Construir prompt OpenAI')[0].json;
const resp = $json;

function extractText(r) {
  if (typeof r.output_text === 'string') return r.output_text;
  if (Array.isArray(r.output)) {
    const texts = [];
    for (const out of r.output) {
      if (Array.isArray(out.content)) {
        for (const c of out.content) {
          if (typeof c.text === 'string') texts.push(c.text);
        }
      }
    }
    if (texts.length) return texts.join('\n');
  }
  return JSON.stringify(r);
}

let raw = extractText(resp);
let ai;
try {
  ai = JSON.parse(raw);
} catch (e) {
  ai = {
    intent: "ambiguous",
    confidence: 0,
    sentiment: "No detectado",
    summary: "No se pudo parsear la respuesta de IA.",
    notes: `Respuesta IA inválida: ${raw}`,
    extracted_follow_up_date: null
  };
}

const currentStatus = base.issueStatus;
let decision = {
  targetStatus: currentStatus,
  resetTouchCounter: false,
  clearDueDate: false,
  autoReply: false,
  replyTemplate: null,
  alertAdmin: false,
  alertReason: null,
  nextAction: 'Revisión pendiente',
  shouldTransition: false
};

const confidence = Number(ai.confidence || 0);
if (confidence < base.config.confidenceThreshold.review) {
  decision.alertAdmin = true;
  decision.alertReason = 'Baja confianza de interpretación IA';
  decision.targetStatus = currentStatus;
  decision.shouldTransition = false;
  decision.autoReply = false;
} else {
  switch (ai.intent) {
    case 'accepts_proposal':
      decision = { targetStatus:'Propuesta aceptada', resetTouchCounter:true, clearDueDate:true, autoReply:true, replyTemplate:'proposal_accepted', alertAdmin:true, alertReason:'Lead acepta la propuesta', nextAction:'Preparar contrato y primera factura', shouldTransition:true };
      break;
    case 'signed':
      decision = { targetStatus:'Firmado', resetTouchCounter:true, clearDueDate:true, autoReply:false, replyTemplate:null, alertAdmin:true, alertReason:'Lead indica firma o formalización', nextAction:'Iniciar onboarding/kickoff', shouldTransition:true };
      break;
    case 'asks_question':
      decision = { targetStatus:'En conversación', resetTouchCounter:true, clearDueDate:true, autoReply:false, replyTemplate:null, alertAdmin:true, alertReason:'Pregunta o aclaración del lead', nextAction:'Administrador debe responder personalmente', shouldTransition:true };
      break;
    case 'price_objection':
      decision = { targetStatus:'En conversación', resetTouchCounter:true, clearDueDate:true, autoReply:false, replyTemplate:null, alertAdmin:true, alertReason:'Objeción de precio', nextAction:'Gestionar objeción comercial con prioridad', shouldTransition:true };
      break;
    case 'requests_technical_meeting':
      decision = { targetStatus:'Reunión devs pendiente', resetTouchCounter:true, clearDueDate:true, autoReply:true, replyTemplate:'technical_meeting', alertAdmin:true, alertReason:'Solicita llamada con equipo técnico', nextAction:'Coordinar agenda con developers', shouldTransition:true };
      break;
    case 'postpones':
      decision = { targetStatus:'A la espera', resetTouchCounter:true, clearDueDate:false, autoReply:true, replyTemplate:'postponed', alertAdmin:false, alertReason:null, nextAction: ai.extracted_follow_up_date ? `Retomar contacto en ${ai.extracted_follow_up_date}` : 'Retomar más adelante; fecha no especificada', shouldTransition:true };
      break;
    case 'rejects':
      decision = { targetStatus:'Descartado', resetTouchCounter:true, clearDueDate:true, autoReply:true, replyTemplate:'rejected', alertAdmin:false, alertReason:null, nextAction:'Lead cerrado por rechazo', shouldTransition:true };
      break;
    case 'ambiguous':
    default:
      decision = { targetStatus: currentStatus, resetTouchCounter:false, clearDueDate:false, autoReply:false, replyTemplate:null, alertAdmin:true, alertReason:'Mensaje ambiguo o no concluyente', nextAction:'Interpretación humana requerida', shouldTransition:false };
      break;
  }
}

return [{ json: { ...base, ai, decision, openaiRaw: resp } }];

const f = $json.jiraFields;
const ai = $json.ai;
const d = $json.decision;
const today = new Date().toISOString().slice(0, 10);

const fields = {
  [f.fechaUltimoContacto]: today,
  [f.gmailThreadId]: $json.gmailThreadId,
  [f.ultimoMessageIdProcesado]: $json.gmailMessageId,
  [f.sentimiento]: { value: ai.sentiment || 'No detectado' },
  [f.resumenConversacion]: ai.summary || '',
  [f.proximaAccion]: d.nextAction
};

if (d.resetTouchCounter) fields[f.numeroToque] = { value: 'Sin toque' };
if (d.clearDueDate) fields[f.fechaVencimiento] = null;

return [{ json: { ...$json, jiraUpdatePayload: { fields } } }];
